import{c as e,Q as l,j as a,m as d}from"./chunks/framework.CQqJojvj.js";const y=JSON.parse('{"title":"13 - 数据结构与算法","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/13-datastructures.md","filePath":"bagu/13-datastructures.md","lastUpdated":null}'),n={name:"bagu/13-datastructures.md"};function i(s,t,r,g,o,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="_13-数据结构与算法" tabindex="-1">13 - 数据结构与算法 <a class="header-anchor" href="#_13-数据结构与算法" aria-label="Permalink to &quot;13 - 数据结构与算法&quot;">​</a></h1><blockquote><p>数据结构与算法是编程基础。面试中常见的排序、树、图等知识点会在此梳理。</p></blockquote><hr><h2 id="_1-常见排序算法" tabindex="-1">1. 常见排序算法 <a class="header-anchor" href="#_1-常见排序算法" aria-label="Permalink to &quot;1. 常见排序算法&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">算法</th><th style="text-align:left;">最好</th><th style="text-align:left;">平均</th><th style="text-align:left;">最差</th><th style="text-align:left;">空间</th><th style="text-align:center;">稳定</th></tr></thead><tbody><tr><td style="text-align:left;">快速排序</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n²)</td><td style="text-align:left;">O(log n)</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;">归并排序</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n)</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;">堆排序</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(n log n)</td><td style="text-align:left;">O(1)</td><td style="text-align:center;">❌</td></tr><tr><td style="text-align:left;">冒泡排序</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(n²)</td><td style="text-align:left;">O(n²)</td><td style="text-align:left;">O(1)</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;">插入排序</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(n²)</td><td style="text-align:left;">O(n²)</td><td style="text-align:left;">O(1)</td><td style="text-align:center;">✅</td></tr><tr><td style="text-align:left;">计数排序</td><td style="text-align:left;">O(n+k)</td><td style="text-align:left;">O(n+k)</td><td style="text-align:left;">O(n+k)</td><td style="text-align:left;">O(n+k)</td><td style="text-align:center;">✅</td></tr></tbody></table><p><strong>Java 中的 Arrays.sort()：</strong></p><ul><li>基本类型用<strong>双轴快排</strong>（Dual-Pivot QuickSort）</li><li>对象类型用<strong>TimSort</strong>（归并 + 插入的混合排序）</li></ul><hr><h2 id="_2-常见数据结构" tabindex="-1">2. 常见数据结构 <a class="header-anchor" href="#_2-常见数据结构" aria-label="Permalink to &quot;2. 常见数据结构&quot;">​</a></h2><h3 id="树" tabindex="-1">树 <a class="header-anchor" href="#树" aria-label="Permalink to &quot;树&quot;">​</a></h3><p><strong>二叉搜索树（BST）：</strong> 左 &lt; 根 &lt; 右，但可能退化为链表。</p><p><strong>平衡二叉树（AVL）：</strong> 左右子树高度差 ≤ 1，通过旋转维持平衡，查找快但插入删除旋转开销大。</p><p><strong>红黑树：</strong> 通过颜色约束（根黑、无连续红、黑高一致）维持近似平衡。插入删除旋转次数少（最多3次），JDK 的 TreeMap/HashMap(树化)、ConcurrentHashMap 都使用红黑树。</p><p><strong>B/B+树：</strong> 多路搜索树，每个节点存储多个键值，减少树高度和磁盘 IO。B+树所有数据在叶子层，且有链表串联，适合范围查询。MySQL InnoDB 使用 B+树。</p><h3 id="堆" tabindex="-1">堆 <a class="header-anchor" href="#堆" aria-label="Permalink to &quot;堆&quot;">​</a></h3><p><strong>大顶堆 / 小顶堆</strong> 用于 Top K 问题、优先级队列。JDK <code>PriorityQueue</code> 基于小顶堆实现。</p><h3 id="跳表-skiplist" tabindex="-1">跳表（SkipList） <a class="header-anchor" href="#跳表-skiplist" aria-label="Permalink to &quot;跳表（SkipList）&quot;">​</a></h3><p>多级索引的链表，期望复杂度 O(log n)，Redis ZSet 使用跳表实现。</p><hr><h2 id="_3-常见算法思想" tabindex="-1">3. 常见算法思想 <a class="header-anchor" href="#_3-常见算法思想" aria-label="Permalink to &quot;3. 常见算法思想&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">思想</th><th style="text-align:left;">核心思路</th><th style="text-align:left;">典型问题</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>双指针</strong></td><td style="text-align:left;">快慢指针/左右指针</td><td style="text-align:left;">链表找环、有序数组 two sum</td></tr><tr><td style="text-align:left;"><strong>滑动窗口</strong></td><td style="text-align:left;">维护一个可变的窗口</td><td style="text-align:left;">最长无重复子串</td></tr><tr><td style="text-align:left;"><strong>二分查找</strong></td><td style="text-align:left;">每次排除一半</td><td style="text-align:left;">旋转排序数组查找</td></tr><tr><td style="text-align:left;"><strong>动态规划</strong></td><td style="text-align:left;">记忆化 + 状态转移</td><td style="text-align:left;">背包、最长公共子序列</td></tr><tr><td style="text-align:left;"><strong>回溯</strong></td><td style="text-align:left;">递归尝试所有可能 + 剪枝</td><td style="text-align:left;">全排列、N皇后、组合总和</td></tr><tr><td style="text-align:left;"><strong>贪心</strong></td><td style="text-align:left;">每步做最优选择</td><td style="text-align:left;">区间调度、跳跃游戏</td></tr><tr><td style="text-align:left;"><strong>分治</strong></td><td style="text-align:left;">分解→解决→合并</td><td style="text-align:left;">归并排序</td></tr></tbody></table><hr><h2 id="_4-时间复杂度速查" tabindex="-1">4. 时间复杂度速查 <a class="header-anchor" href="#_4-时间复杂度速查" aria-label="Permalink to &quot;4. 时间复杂度速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">数据结构</th><th style="text-align:left;">访问</th><th style="text-align:left;">搜索</th><th style="text-align:left;">插入</th><th style="text-align:left;">删除</th></tr></thead><tbody><tr><td style="text-align:left;">数组</td><td style="text-align:left;">O(1)</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(n)</td></tr><tr><td style="text-align:left;">链表</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(1)</td><td style="text-align:left;">O(1)</td></tr><tr><td style="text-align:left;">跳表</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td></tr><tr><td style="text-align:left;">哈希表</td><td style="text-align:left;">—</td><td style="text-align:left;">O(1)</td><td style="text-align:left;">O(1)</td><td style="text-align:left;">O(1)</td></tr><tr><td style="text-align:left;">BST（平衡）</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td></tr><tr><td style="text-align:left;">二叉堆</td><td style="text-align:left;">O(1) (peek)</td><td style="text-align:left;">O(n)</td><td style="text-align:left;">O(log n)</td><td style="text-align:left;">O(log n)</td></tr></tbody></table><hr><h2 id="_5-算法刷题要点" tabindex="-1">5. 算法刷题要点 <a class="header-anchor" href="#_5-算法刷题要点" aria-label="Permalink to &quot;5. 算法刷题要点&quot;">​</a></h2><h3 id="链表" tabindex="-1">链表 <a class="header-anchor" href="#链表" aria-label="Permalink to &quot;链表&quot;">​</a></h3><ul><li>虚拟头节点（Dummy Node）</li><li>快慢指针（找中点、判环）</li><li>反转链表（迭代 + 递归）</li></ul><h3 id="二叉树" tabindex="-1">二叉树 <a class="header-anchor" href="#二叉树" aria-label="Permalink to &quot;二叉树&quot;">​</a></h3><ul><li>前中后序遍历（递归 + 迭代 + Morris）</li><li>层序遍历（BFS + Queue）</li><li>最近公共祖先 LCA</li></ul><h3 id="动态规划" tabindex="-1">动态规划 <a class="header-anchor" href="#动态规划" aria-label="Permalink to &quot;动态规划&quot;">​</a></h3><ul><li>解题框架：状态定义 → 转移方程 → 初始值 → 遍历顺序 → 输出</li><li>背包九讲：0-1背包、完全背包、多重背包</li><li>子序列 DP：最长递增子序列、最长公共子序列</li></ul><h3 id="回溯" tabindex="-1">回溯 <a class="header-anchor" href="#回溯" aria-label="Permalink to &quot;回溯&quot;">​</a></h3><ul><li><code>void backtrack(路径, 选择列表)</code> 模板</li><li>排列（讲究顺序）、组合（不讲究顺序）、子集</li></ul>',34)])])}const h=e(n,[["render",i]]);export{y as __pageData,h as default};
